+        use std::collections::HashSet;
+        let k = IdempotencyKey::from_raw(12345);
+        let k2 = k; // Copy
+        let k3 = k.clone();
+        assert_eq!(k, k2);
+        assert_eq!(k, k3);
+        assert_ne!(k, IdempotencyKey::from_raw(99999));
+        let dbg = format!("{k:?}");
+        assert!(dbg.contains("12345"));
+        let mut set = HashSet::new();
+        set.insert(k);
+        assert!(set.contains(&k2));
